impl Solution { pub fn max_length(arr: Vec<String>) -> i32 { let mut black_masks = vec![0u32]; for s in arr { let mut m = 0u32; for b in s.bytes() { let bit = 1 << (b - b'a'); if m & bit != 0 { m = 0; break; } m |= bit; } if m != 0 { for i in 0..black_masks.len() { if black_masks[i] & m == 0 { black_masks.push(black_masks[i] | m); } } } } black_masks.iter().map(|m| m.count_ones() as i32).max().unwrap_or(0) } }